package Day2;

public class ForloopEx {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		/*
		 * for (int i =1;i<=10;i++) { if(i==5) { //continue; break; }
		 * System.out.println(i);
		 * 
		 * }
		 */
		
		for (int i=10;i>=1;i--) {
			System.out.println(i);
		}
		
		

	}

}
